const CACHE_NAME="gys-cache-v52",APP_VERSION="3.7.0";self.addEventListener("install",e=>{self.skipWaiting()}),self.addEventListener("activate",e=>{e.waitUntil(caches.keys().then(t=>Promise.all(t.map(a=>{if(a!==CACHE_NAME)return caches.delete(a)}))).then(()=>self.clients.claim()))}),self.addEventListener("message",e=>{e.data&&e.data.type==="GET_VERSION"&&e.source.postMessage({type:"VERSION",version:APP_VERSION}),e.data&&e.data.type==="CLEAR_CACHE"&&caches.keys().then(t=>Promise.all(t.map(a=>caches.delete(a)))).then(()=>{e.source.postMessage({type:"CACHE_CLEARED"})})}),self.addEventListener("fetch",e=>{const t=new URL(e.request.url);if(t.pathname.includes("/midi/")||t.pathname.includes("/pdf/")||t.pathname.includes("/chord/")||t.pathname.includes("assets-list.json")){e.respondWith(fetch(e.request));return}if(e.request.method!=="GET")return;if(t.origin===self.location.origin&&(t.pathname.endsWith(".js")||t.pathname.endsWith(".css")||t.pathname.endsWith(".html")||t.pathname==="/"||t.pathname.endsWith("/"))){e.respondWith(caches.open(CACHE_NAME).then(r=>fetch(e.request).then(s=>(s&&s.status===200&&r.put(e.request,s.clone()),s)).catch(()=>caches.match(e.request).then(s=>s||Response.error()))));return}e.respondWith(caches.match(e.request).then(r=>r||fetch(e.request).then(s=>{if(s&&(s.status===200||s.type==="opaque")){const i=s.clone();caches.open(CACHE_NAME).then(c=>{c.put(e.request,i)})}return s}).catch(s=>(console.warn("Network fetch failed for",e.request.url,s),Response.error()))))});

